    box-shadow: 0 0 15px rgba(105, 240, 174, 0.4);
}

body[data-theme="tropical"] .filter-btn {
    border-radius: 20px;
}

body[data-theme="tropical"] .filter-btn.active {
    background: linear-gradient(135deg, var(--accent-green), var(--accent-teal));
    box-shadow: 0 4px 15px rgba(105, 240, 174, 0.4);
}

body[data-theme="tropical"] .cost-bar,
body[data-theme="tropical"] .device-card {
